import java.io.*;

public class ImageConverter {
    public static void convertImage(String inputFileName, String outputFileName, String format) throws IOException {
        ProcessBuilder pb = new ProcessBuilder("convert", inputFileName, "-output", outputFileName + "." + format);
        Process process = pb.start();

        InputStream inputStream = process.getErrorStream();
        BufferedReader errorReader = new BufferedReader(new InputStreamReader(inputStream));
        String line;
        while ((line = errorReader.readLine()) != null) {
            System.out.println("Error: " + line);
        }

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new IOException("convert exited with error code " + exitCode);
        }
    }
}